### Methods

```ts
on(event: string, fn: (data: any) => void): this
emit(event: string, data?: any): void
```

### Example

```ts
const emitter = new ZYNQ.EventEmitter();

emitter.on('ready', (id) => {
  console.log('Ready:', id);
});

emitter.emit('ready', { id: 'peer-123' });
```

### Methods

```ts
connect(remoteId: string): this
send(data: any): void
getStream(): Promise<MediaStream | null>
close(): void
destroy(): void
```

### Example

```ts
const peer = new ZYNQ.Peer();

peer.on('ready', (id) => {
  peer.connect('remote-123');
});

peer.on('data', (msg) => {
  console.log('Message:', msg);
});

peer.send('hello world');
```

### Events

```ts
ready: string
open: string
data: any
stream: MediaStream
close: void
error: { type: string, error: any }
reconnecting: { attempt: number, delay: number }
```

### Example

```ts
peer.on('stream', (stream) => {
  video.srcObject = stream;
});

peer.on('reconnecting', (info) => {
  console.log('Reconnect attempt:', info.attempt);
});
```
